tools.implBody:
const data = await vendorFetch<{ user: any }>({
      bearer,
      method: "GET",
      path: "/get_current_user",
    });
    const u = data.user ?? {};
    return NextResponse.json({
      user: {
        id: u.id,
        first_name: u.first_name ?? null,
        last_name: u.last_name ?? null,
        email: u.email ?? null,
        registration_status: u.registration_status ?? null,
        default_currency: u.default_currency ?? null,
        country_code: u.country_code ?? null,
        picture_url: u.picture?.medium ?? u.picture?.small ?? null,
      },
    });

const data = await vendorFetch<{ groups: any[] }>({
      bearer,
      method: "GET",
      path: "/get_groups",
    });
    const groups = (data.groups ?? []).map((g: any) => ({
      id: g.id,
      name: g.name,
      group_type: g.group_type ?? null,
      updated_at: g.updated_at ?? null,
      simplify_by_default: g.simplify_by_default === true,
      member_count: Array.isArray(g.members) ? g.members.length : null,
      members: Array.isArray(g.members)
        ? g.members.map((m: any) => ({
            id: m.id,
            first_name: m.first_name ?? null,
            last_name: m.last_name ?? null,
            balance: Array.isArray(m.balance) ? m.balance : [],
          }))
        : [],
    }));
    return NextResponse.json({ groups, count: groups.length });

const data = await vendorFetch<{ friends: any[] }>({
      bearer,
      method: "GET",
      path: "/get_friends",
    });
    const friends = (data.friends ?? []).map((f: any) => ({
      id: f.id,
      first_name: f.first_name ?? null,
      last_name: f.last_name ?? null,
      email: f.email ?? null,
      registration_status: f.registration_status ?? null,
      balance: Array.isArray(f.balance) ? f.balance : [],
      groups: Array.isArray(f.groups)
        ? f.groups.map((g: any) => ({ group_id: g.group_id, balance: g.balance }))
        : [],
    }));
    return NextResponse.json({ friends, count: friends.length });

const b = body as any;
    const query: Record<string, string | number | undefined> = {
      limit: Math.min(b.limit ?? 20, 100),
      offset: b.offset ?? 0,
    };
    if (b.group_id !== undefined) query.group_id = b.group_id;
    if (b.friend_id !== undefined && b.group_id === undefined) query.friend_id = b.friend_id;
    if (b.dated_after) query.dated_after = b.dated_after;
    if (b.dated_before) query.dated_before = b.dated_before;
    const data = await vendorFetch<{ expenses: any[] }>({
      bearer,
      method: "GET",
      path: "/get_expenses",
      query,
    });
    const expenses = (data.expenses ?? []).map((e: any) => ({
      id: e.id,
      group_id: e.group_id ?? null,
      description: e.description ?? null,
      cost: e.cost ?? null,
      currency_code: e.currency_code ?? null,
      date: e.date ?? null,
      created_at: e.created_at ?? null,
      payment: e.payment === true,
      deleted_at: e.deleted_at ?? null,
      created_by: e.created_by ? { id: e.created_by.id, first_name: e.created_by.first_name } : null,
      users: Array.isArray(e.users)
        ? e.users.map((u: any) => ({
            user_id: u.user_id ?? u.user?.id ?? null,
            first_name: u.user?.first_name ?? null,
            paid_share: u.paid_share,
            owed_share: u.owed_share,
            net_balance: u.net_balance,
          }))
        : [],
    }));
    return NextResponse.json({ expenses, count: expenses.length });

const b = body as any;
    if (b.simulate) {
      return NextResponse.json({
        expense_id: null,
        status: "preview",
        group_id: b.group_id,
        cost: b.cost,
        currency_code: b.currency_code ?? null,
        description: b.description,
        simulated: true,
        note: "Will be split equally among everyone in the group. You will be recorded as the payer.",
      });
    }
    const payload: Record<string, unknown> = {
      cost: String(b.cost),
      description: String(b.description),
      group_id: b.group_id,
      split_equally: true,
    };
    if (b.currency_code) payload.currency_code = String(b.currency_code).toUpperCase();
    if (b.date) payload.date = String(b.date);
    if (b.category_id !== undefined) payload.category_id = b.category_id;
    if (b.details) payload.details = String(b.details);
    const result = await vendorFetch<{ expenses: any[]; errors?: any }>({
      bearer,
      method: "POST",
      path: "/create_expense",
      body: payload,
    });
    const errs = result.errors;
    const hasErrors = errs && ((Array.isArray(errs.base) && errs.base.length > 0) || Object.keys(errs).some((k) => Array.isArray((errs as any)[k]) && (errs as any)[k].length > 0));
    if (hasErrors) {
      throw new VendorApiError(422, errs, `Splitwise create_expense returned errors: ${JSON.stringify(errs).slice(0, 240)}`);
    }
    const created = (result.expenses ?? [])[0] ?? {};
    return NextResponse.json({
      expense_id: created.id ?? null,
      status: created.id ? "created" : "unknown",
      description: created.description ?? b.description,
      cost: created.cost ?? b.cost,
      currency_code: created.currency_code ?? null,
      group_id: created.group_id ?? b.group_id,
      date: created.date ?? null,
    });

const b = body as any;
    if (b.simulate) {
      return NextResponse.json({
        success: true,
        expense_id: b.expense_id,
        simulated: true,
        note: "Will mark this expense as deleted. Splitwise lets you undelete from the app within ~30 days.",
      });
    }
    const result = await vendorFetch<{ success: boolean; errors?: any }>({
      bearer,
      method: "POST",
      path: `/delete_expense/${b.expense_id}`,
    });
    if (!result.success) {
      throw new VendorApiError(422, result.errors ?? null, `Splitwise delete_expense returned success=false: ${JSON.stringify(result.errors ?? {}).slice(0, 240)}`);
    }
    return NextResponse.json({ success: true, expense_id: b.expense_id });
